import { useEffect, useState } from "react"
function Movies() {
    useEffect(() => {
        async function getmovies() {
            let movieslist = []
            for(let i = 1; i <= 5; i++) {
                let fetchmov = await fetch(`https://api.themoviedb.org/3/movie/popular?api_key=438b5d80663af506dbe9658849a35777&language=en-US&page=${i}`)
                let jsonfetchmov = await fetchmov.json()
                movieslist.push(jsonfetchmov)
            }
            console.log(movieslist)
        }
        getmovies()
    }, [])
    return<>
    <img src="https://image.tmdb.org/t/p/w500/8UlWHLMpgZm9bx6QYh0NFoq67TZ.jpg"/>
    </>
}
export default Movies
